 1	import type { FC } from 'react';
 2	import { DetailsItem } from 'src/components/DetailItems/DetailItem';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import EditProviderVDDKImage from 'src/providers/details/tabs/Details/components/DetailsSection/EditProviderVDDKImage';
 5	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
 6	
 7	import { Label } from '@patternfly/react-core';
 8	import { ExclamationTriangleIcon } from '@patternfly/react-icons';
 9	
10	import type { ProviderDetailsItemProps } from './ProviderDetailsItem';
11	
12	export const VDDKDetailsItem: FC<ProviderDetailsItemProps> = ({
13	  canPatch,
14	  helpContent,
15	  moreInfoLink,
16	  resource: provider,
17	}) => {
18	  const { t } = useForkliftTranslation();
19	  const { showModal } = useModal();
20	
21	  const defaultMoreInfoLink =
22	    'https://docs.redhat.com/en/documentation/migration_toolkit_for_virtualization/2.9/html-single/installing_and_using_the_migration_toolkit_for_virtualization/index#creating-vddk-image_mtv';
23	  const defaultHelpContent = (
24	    <ForkliftTrans>
25	      Virtual Disk Development Kit (VDDK) container init image path. The path must be empty or a
26	      valid container image path in the format of{' '}
27	      <strong>registry_route_or_server_path/vddk:&#8249;tag&#8250;</strong>.<br />
28	      <br />
29	      To accelerate migration and reduce the risk of a plan failing, it is strongly recommended to
30	      specify a VDDK init image.
31	    </ForkliftTrans>
32	  );
33	
34	  return (
35	    <DetailsItem
36	      testId="vddk-detail-item"
37	      title={t('VDDK init image')}
38	      content={
39	        provider?.spec?.settings?.vddkInitImage ?? (
40	          <Label isCompact color={'orange'}>
41	            <ExclamationTriangleIcon color="#F0AB00" />
42	            <span className="forklift-section-provider-empty-vddk-label-text">{t('Empty')}</span>
43	          </Label>
44	        )
45	      }
46	      moreInfoLink={moreInfoLink ?? defaultMoreInfoLink}
47	      helpContent={helpContent ?? defaultHelpContent}
48	      crumbs={['Provider', 'spec', 'settings', 'vddkInitImage']}
49	      onEdit={() => {
50	        showModal(<EditProviderVDDKImage resource={provider} />);
51	      }}
52	      canEdit={canPatch}
53	    />
54	  );
55	};

